def norm(a):
    """Normalize a to [0, MOD)"""
    return (a % MOD + MOD) % MOD

def mul(a, b):
    """Modular multiplication"""
    return norm(a * b)

def getHash(l, r):
    """Get hash of s[l:r+1]"""
    return norm(h[r+1] - mul(h[l], pw[r-l+1]))

def precalc(s):
    """Precompute hashes and powers"""
    n = len(s)
    h = [0] * (n + 1)
    pw = [1] * (n + 1)
    for i in range(n):
        h[i+1] = mul(h[i], BASE) + ord(s[i]) - ord('a') + 1
        pw[i+1] = mul(pw[i], BASE)
    return h, pw

def solve(n, s):
    """Main solver"""
    h, pw = precalc(s)

    def get_hash(l, r):
        return norm(h[r+1] - mul(h[l], pw[r-l+1]))

    result = []
    for k in range(1, n // 2 + 1):
        # k-substring is s[k-1 : n-k+1]
        start = k - 1
        end = n - k
        length = end - start + 1

        # Find the longest odd-length border
        for odd_len in range(length - 1, 0, -2):
            if get_hash(start, start + odd_len - 1) == get_hash(end - odd_len + 1, end):
                result.append(odd_len)
                break
        else:
            result.append(-1)

    return result
